CREATE TABLE "country_section_mappings" (
  "id" TEXT PRIMARY KEY,
  "country_code" TEXT NOT NULL,
  "superset_code" TEXT NOT NULL,
  "heading" TEXT NOT NULL,
  "created_at" TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  "updated_at" TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE UNIQUE INDEX "country_section_mappings_country_code_superset_code_key" ON "country_section_mappings" ("country_code", "superset_code");

